bool Questions::validJsonOfField(size_t index, const std::string& fieldName,
                                 const Json::Value& pJson, std::string& err,
                                 bool isForCreation) {
  switch (index) {
    case 0:
      if (pJson.isNull()) {
        err = "The " + fieldName + " column cannot be null";
        return false;
      }
      if (isForCreation) {
        err = "The automatic primary key cannot be set";
        return false;
      }
      if (!pJson.isInt64()) {
        err = "Type error in the " + fieldName + " field";
        return false;
      }
      break;
    case 1:
      if (pJson.isNull()) {
        err = "The " + fieldName + " column cannot be null";
        return false;
      }
      if (!pJson.isString()) {
        err = "Type error in the " + fieldName + " field";
        return false;
      }
      break;
    case 2:
      if (pJson.isNull()) {
        err = "The " + fieldName + " column cannot be null";
        return false;
      }
      if (!pJson.isInt64()) {
        err = "Type error in the " + fieldName + " field";
        return false;
      }
      break;
    case 3:
      if (pJson.isNull()) {
        err = "The " + fieldName + " column cannot be null";
        return false;
      }
      if (!pJson.isString()) {
        err = "Type error in the " + fieldName + " field";
        return false;
      }
      break;
    case 4:
      if (pJson.isNull()) {
        err = "The " + fieldName + " column cannot be null";
        return false;
      }
      if (!pJson.isInt()) {
        err = "Type error in the " + fieldName + " field";
        return false;
      }
      break;
    case 5:
      if (pJson.isNull()) {
        err = "The " + fieldName + " column cannot be null";
        return false;
      }
      if (!pJson.isString()) {
        err = "Type error in the " + fieldName + " field";
        return false;
      }
      break;
    default:
      err = "Internal error in the server";
      return false;
  }
  return true;
}
Categories Questions::getCategory(const DbClientPtr& clientPtr) const {
  static const std::string sql = "select * from categories where id = $1";
  Result r(nullptr);
  {
    auto binder = *clientPtr << sql;
    binder << *categoryId_ << Mode::Blocking >>
        [&r](const Result& result) { r = result; };
    binder.exec();
  }
  if (r.size() == 0) {
    throw UnexpectedRows("0 rows found");
  } else if (r.size() > 1) {
    throw UnexpectedRows("Found more than one row");
  }
  return Categories(r[0]);
}

void Questions::getCategory(const DbClientPtr& clientPtr,
                            const std::function<void(Categories)>& rcb,
                            const ExceptionCallback& ecb) const {
  static const std::string sql = "select * from categories where id = $1";
  *clientPtr << sql << *categoryId_ >> [rcb = std::move(rcb),
                                        ecb](const Result& r) {
    if (r.size() == 0) {
      ecb(UnexpectedRows("0 rows found"));
    } else if (r.size() > 1) {
      ecb(UnexpectedRows("Found more than one row"));
    } else {
      rcb(Categories(r[0]));
    }
  } >> ecb;
}
