std::vector<AnswerOptions> Questions::getAnswerOptions(
    const DbClientPtr& clientPtr) const {
  static const std::string sql =
      "select * from answer_options where question_id = $1";
  Result r(nullptr);
  {
    auto binder = *clientPtr << sql;
    binder << *id_ << Mode::Blocking >>
        [&r](const Result& result) { r = result; };
    binder.exec();
  }
  std::vector<AnswerOptions> ret;
  ret.reserve(r.size());
  for (auto const& row : r) {
    ret.emplace_back(AnswerOptions(row));
  }
  return ret;
}

